+            entry.id
+        );
+    }
+
+    // Capability coverage: at least one extension for each major capability
+    let required_capabilities = [
+        "registerTool",
+        "event_hook",
+        "registerProvider",
+        "ui_header",
+        "registerShortcut",
+        "registerFlag",
+    ];
+    for cap in &required_capabilities {
